### Describe the issue

When using the iGPU of Core Ultra 185H, onnxruntime-web `1.26.0-dev.20260502-9d1492a449` shows 4x worse performance over the previous dev build, `1.26.0-dev.20260416-b7804b056c`. This regression continues to exist in `1.26.0` stable and also the latest dev `1.27.0-dev.20260506-673c3320fc`.

I used Codex to write a minimal reproduction script (see the next section). Here is the result, where the inference time of the `Xenova/bge-base-zh-v1.5` model increases from 529.0ms to 2234.9ms:

<img width="608" height="292" alt="Image" src="https://github.com/user-attachments/assets/19132bba-b606-4ae0-b585-0231cd78fbd0" />

In comparison, I see no significant regression on RTX 4060 Laptop:

<img width="608" height="292" alt="Image" src="https://github.com/user-attachments/assets/16076294-16df-4bc2-989f-f2c2c8ab1784" />

So this regression should specific to intel.

### To reproduce

Save this as HTML, open it, and click Run.

```html
<!doctype html>
<button id="run">Run</button>
<pre id="out"></pre>
<script type="module">
const modelUrl = "https://huggingface.co/Xenova/bge-base-zh-v1.5/resolve/main/onnx/model_fp16.onnx";
let cachedModelUrlPromise;
const cases = [
  ["1.26.0-dev.20260416-b7804b056c"],
  //["ci-20260425-954dbce243", ".ort-ci/954dbce243/dist/"],
  ["1.26.0-dev.20260502-9d1492a449"],
  ["1.26.0"],
  ["1.27.0-dev.20260506-673c3320fc"],
];
const batch = 128, seq = 32, runs = 3, warmup = 1;

async function gpuInfo() {
  const adapter = await navigator.gpu?.requestAdapter();
  if (!adapter) return "GPU: unavailable";
  const info = adapter.info ?? await adapter.requestAdapterInfo?.();
  return `GPU: ${info?.vendor ?? "unknown vendor"} ${info?.architecture ?? ""} ${info?.device ?? ""} ${info?.description ?? ""}`.trim();
}

function feeds(ort) {
  const n = batch * seq;
  const ids = new BigInt64Array(n);
  const zeros = new BigInt64Array(n);
  const mask = new BigInt64Array(n).fill(1n);
  for (let b = 0; b < batch; b++) {
    const row = b * seq;
    ids[row] = 101n;
    ids[row + seq - 1] = 102n;
    for (let s = 1; s < seq - 1; s++) ids[row + s] = BigInt(100 + ((b + s) % 1000));
  }
  const dims = [batch, seq];
  return {
    input_ids: new ort.Tensor("int64", ids, dims),
    attention_mask: new ort.Tensor("int64", mask, dims),
    token_type_ids: new ort.Tensor("int64", zeros, dims),
  };
}

async function getCachedModelUrl() {
  cachedModelUrlPromise ??= fetch(modelUrl)
    .then((response) => {
      if (!response.ok) throw new Error(`failed to fetch model: ${response.status} ${response.statusText}`);
      return response.blob();
    })
    .then((blob) => URL.createObjectURL(blob));
  return cachedModelUrlPromise;
}

async function bench([name, distBase]) {
  const base = distBase ?? `https://cdn.jsdelivr.net/npm/onnxruntime-web@${name}/dist/`;
  const suffix = `?case=${encodeURIComponent(name)}`;
  const ort = await import(`${base}ort.webgpu.min.mjs${suffix}`);
  ort.env.logLevel = "error";
  ort.env.wasm.wasmPaths = {
    wasm: `${base}ort-wasm-simd-threaded.asyncify.wasm`,
    mjs: `${base}ort-wasm-simd-threaded.asyncify.mjs`,
  };
  const session = await ort.InferenceSession.create(await getCachedModelUrl(), {
    executionProviders: [{ name: "webgpu", validationMode: "disabled" }],
    graphOptimizationLevel: "all",
  });
  const input = feeds(ort);
  for (let i = 0; i < warmup; i++) await session.run(input);
  let total = 0;
  for (let i = 0; i < runs; i++) {
    const t0 = performance.now();
    const output = await session.run(input);
    output[session.outputNames[0]].cpuData[0];
    total += performance.now() - t0;
  }
  await session.release?.();
  return `${name}: ${(total / runs).toFixed(1)} ms`;
}

document.querySelector("#run").onclick = async () => {
  const out = document.querySelector("#out");
  out.textContent = `${await gpuInfo()}\n`;
  await getCachedModelUrl();
  out.textContent += "running...\n";
  for (const c of cases) out.textContent += `${await bench(c)}\n`;
  out.textContent += "done.\n";
};
</script>
```

*(20260519: updated the script to cache the .onnx file into blob url, instead of downloading it once per test case)*

